{
  "applicable_policies": [
    {
      "doc_id": "01_expense_reimbursement_2025.md",
      "title": "XX证券费用报销管理办法(2025修订版)",
      "clause_no": "第十一条",
      "clause_text": "不得将同一事项或同类事项拆分为多笔报销以规避审批权限。同一员工、同一费用类型在7天内出现2笔及以上报销,且合计金额达到《授权管理办法》附件二较高审批线的,应重点核查拆分规避审批。",
      "effective_date": "2025-01-01",
      "expiry_date": null,
      "applicability_reason": "2025修订版自2025年1月1日起施行,R004236和R004237的费用发生日期为2025年10月,完全适用"
    },
    {
      "doc_id": "03_authorization_management.md",
      "title": "XX证券授权管理办法",
      "clause_no": "附件二",
      "clause_text": "审批档位: AR-01 0~<3000 部门经理; AR-02 3000~<10000 部门经理+财务复核; AR-03 10000~<50000 部门总经理; AR-04 50000~<200000 分管副总; AR-05 ≥200000 总经理办公会",
      "effective_date": "2025-01-01",
      "expiry_date": null,
      "applicability_reason": "费用报销管理办法第五条引用授权管理办法附件二确定审批线;两笔报销合计¥10,400触发AR-03(较高审批线为¥10,000)"
    }
  ],
  "excluded_policies": [
    {
      "doc_id": "02_expense_reimbursement_2022_deprecated.md",
      "title": "XX证券费用报销管理办法(2022版)",
      "exclusion_reason": "已由2025修订版废止,不适用于2025年10月的费用"
    }
  ],
  "conflicts": [],
  "unresolved_items": []
}

